  /**
   * Returns all known name variants (nicknames + formal names + sibling nicknames) for a given name.
   * Lookup is bidirectional: works from formal name or nickname.
   * Returns [name] if the name is not in the dataset — unknown names only match themselves.
   * NOTE: Does NOT include spelling variants (erik ≠ eric per design).
   */
  export function getNameVariants(name: string): string[] {
    const normalized = name.toLowerCase().trim().replace(/[^a-z]/g, '');
    return NICKNAME_LOOKUP[normalized] ?? [normalized];
  }
  